// Bloqueia o menu de contexto (clique direito)
document.addEventListener("contextmenu", function(e) {
    e.preventDefault();
});

// Bloqueia atalhos de teclado comuns para ferramentas de desenvolvimento
document.addEventListener("keydown", function(e) {
    if (e.key === "F12") e.preventDefault();
    if (e.ctrlKey && e.shiftKey && e.key === "I") e.preventDefault();
    if (e.ctrlKey && e.key === "u") e.preventDefault();
    if (e.ctrlKey && e.shiftKey && e.key === "J") e.preventDefault();
    if (e.ctrlKey && e.shiftKey && e.key === "C") e.preventDefault();
    if (e.ctrlKey && e.key === "s") e.preventDefault();
    if (e.ctrlKey && e.key === "p") e.preventDefault();
});

// ── Detecção de DevTools (SEM usar tamanho de janela) ──────────────
const devtools = { open: false };
const element = new Image();
Object.defineProperty(element, 'id', {
    get: function () {
        devtools.open = true;
    }
});

// Monitoramento contínuo via console trick
console.log('%c', element);
setInterval(function() {
    // Reseta o trigger a cada ciclo
    console.log('%c', element);

    if (devtools.open) {
        document.body.innerHTML = '<h1>Acesso não autorizado detectado</h1>';
        devtools.open = false;
    }
}, 1000);

// Impede seleção de texto
document.addEventListener('selectstart', function(e) {
    e.preventDefault();
});

// Impede arrastar e soltar
document.addEventListener('dragstart', function(e) {
    e.preventDefault();
});

// Ofusca console
console.log = function() {};
console.debug = function() {};
console.info = function() {};